"use client";

import { useEffect, useRef, useCallback } from "react";

interface Node {
  layer: number;
  index: number;
  x: number;
  y: number;
  baseRadius: number;
  phase: number;
  pulse: number;
  cascadeGlow: number;
}

interface Edge {
  from: Node;
  to: Node;
  cpx: number;
  cpy: number;
  isSkip: boolean;
}

const TAU = Math.PI * 2;
const LAYERS = [5, 7, 9, 7, 5];

const CASCADE_INTERVAL_MIN = 8;
const CASCADE_INTERVAL_MAX = 14;
const CASCADE_DURATION = 2.0;

const COL = {
  nodeFill: "hsla(205, 55%, 72%, 0.72)",
  nodeStroke: "hsla(205, 45%, 82%, 0.45)",
  nodeGlow: "hsla(200, 60%, 68%, 0.20)",
  nodeCascade: "hsla(195, 70%, 68%, 0.80)",
  nodeCascadeGlow: "hsla(195, 70%, 65%, 0.25)",
  edge: "hsla(210, 40%, 62%, 0.30)",
  edgeSkip: "hsla(210, 35%, 55%, 0.18)",
  edgeCascade: "hsla(195, 50%, 65%, 0.40)",
};

export default function NeuralNetworkField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const stateRef = useRef<{
    nodes: Node[];
    edges: Edge[];
    width: number;
    height: number;
    cascadeUntil: number;
    nextCascade: number;
  } | null>(null);

  const initState = useCallback((width: number, height: number) => {
    const padX = 140;
    const padY = 100;
    const availW = width - padX * 2;
    const availH = height - padY * 2;
    const maxNodes = Math.max(...LAYERS);
    const nodeSpacingY = availH / (maxNodes + 1);

    // Create nodes
    const nodes: Node[] = [];
    for (let l = 0; l < LAYERS.length; l++) {
      const count = LAYERS[l];
      const layerX = padX + (availW * l) / (LAYERS.length - 1);
      const startY = padY + (availH - (count - 1) * nodeSpacingY) / 2;
      for (let i = 0; i < count; i++) {
        nodes.push({
          layer: l,
          index: i,
          x: layerX,
          y: startY + i * nodeSpacingY,
          baseRadius: 2.0 + Math.random() * 0.5,
          phase: Math.random() * TAU,
          pulse: 0,
          cascadeGlow: 0,
        });
      }
    }

    // Build edges — fully connected between adjacent layers
    const edges: Edge[] = [];
    const nodeByLayer = (l: number) => nodes.filter((n) => n.layer === l);

    for (let l = 0; l < LAYERS.length - 1; l++) {
      const fromNodes = nodeByLayer(l);
      const toNodes = nodeByLayer(l + 1);
      for (const from of fromNodes) {
        for (const to of toNodes) {
          const midX = (from.x + to.x) / 2;
          const midY = (from.y + to.y) / 2;
          const dy = to.y - from.y;
          const bow = Math.min(60, Math.abs(dy) * 0.3 + 15) * (dy > 0 ? 1 : -1);
          edges.push({
            from,
            to,
            cpx: midX,
            cpy: midY + bow * (0.6 + Math.random() * 0.5),
            isSkip: false,
          });
        }
      }
    }

    // Skip connections for visual depth
    const skipPairs: [number, number][] = [[0, 2], [1, 3], [2, 4]];
    for (const [la, lb] of skipPairs) {
      const fromNodes = nodeByLayer(la);
      const toNodes = nodeByLayer(lb);
      for (let i = 0; i < Math.min(fromNodes.length, toNodes.length); i++) {
        const from = fromNodes[i];
        const to = toNodes[i];
        const midX = (from.x + to.x) / 2;
        const midY = (from.y + to.y) / 2;
        edges.push({
          from,
          to,
          cpx: midX,
          cpy: midY + (Math.random() - 0.5) * 40,
          isSkip: true,
        });
      }
    }

    return {
      nodes,
      edges,
      width,
      height,
      cascadeUntil: 0,
      nextCascade:
        CASCADE_INTERVAL_MIN +
        Math.random() * (CASCADE_INTERVAL_MAX - CASCADE_INTERVAL_MIN),
    };
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: true });
    if (!ctx) return;

    let animationId = 0;
    let dpr = 1;
    let width = 0;
    let height = 0;
    let resizeTimer: ReturnType<typeof setTimeout> | null = null;

    const resize = () => {
      dpr = Math.min(window.devicePixelRatio || 1, 2);
      width = window.innerWidth;
      height = window.innerHeight;
      canvas.width = Math.floor(width * dpr);
      canvas.height = Math.floor(height * dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      stateRef.current = initState(width, height);
    };

    const debouncedResize = () => {
      if (resizeTimer) clearTimeout(resizeTimer);
      resizeTimer = setTimeout(resize, 200);
    };

    const draw = (timestamp: number) => {
      const s = stateRef.current;
      if (!s) {
        animationId = requestAnimationFrame(draw);
        return;
      }

      const now = timestamp * 0.001;

      // ── Cascade logic ──────────────────────────────────────────────────

      if (now > s.nextCascade) {
        s.cascadeUntil = now + CASCADE_DURATION;
        s.nextCascade =
          now +
          CASCADE_INTERVAL_MIN +
          Math.random() * (CASCADE_INTERVAL_MAX - CASCADE_INTERVAL_MIN);
      }

      const cascadeProgress =
        s.cascadeUntil > now
          ? 1 - (s.cascadeUntil - now) / CASCADE_DURATION
          : -1;
      const inCascade = cascadeProgress >= 0;
      const waveFront = inCascade ? cascadeProgress * (LAYERS.length - 1) : -1;

      // ── Update nodes ───────────────────────────────────────────────────

      for (const node of s.nodes) {
        node.pulse = Math.sin(now * 1.3 + node.phase) * 0.18;
        const distFromWave = inCascade ? Math.abs(node.layer - waveFront) : 999;
        const gauss = Math.exp(-(distFromWave * distFromWave) / 0.7);
        node.cascadeGlow = inCascade
          ? Math.max(0, gauss * (1 - Math.abs(cascadeProgress - 0.5) * 2))
          : 0;
      }

      // ── Draw ───────────────────────────────────────────────────────────

      ctx.clearRect(0, 0, s.width, s.height);

      // Edges — sorted by layer for back-to-front depth
      const sortedEdges = [...s.edges].sort(
        (a, b) => a.from.layer - b.from.layer,
      );

      for (const edge of sortedEdges) {
        const { from, to } = edge;

        let edgeAlpha = edge.isSkip ? 0.16 : 0.28;
        if (inCascade) {
          const edgeCenter = (from.layer + to.layer) / 2;
          const edgeDist = Math.abs(edgeCenter - waveFront);
          const edgeGauss = Math.exp(-(edgeDist * edgeDist) / 1.2);
          edgeAlpha += edgeGauss * 0.18;
        }

        ctx.globalAlpha = Math.min(0.55, edgeAlpha);
        ctx.strokeStyle = edge.isSkip
          ? COL.edgeSkip
          : inCascade && edgeAlpha > 0.32
            ? COL.edgeCascade
            : COL.edge;
        ctx.lineWidth = edge.isSkip ? 0.5 : 0.7;
        ctx.setLineDash(edge.isSkip ? [3, 5] : []);
        ctx.beginPath();
        ctx.moveTo(from.x, from.y);
        ctx.quadraticCurveTo(edge.cpx, edge.cpy, to.x, to.y);
        ctx.stroke();
      }
      ctx.setLineDash([]);

      // Nodes — sorted by layer for back-to-front depth
      const sortedNodes = [...s.nodes].sort((a, b) => a.layer - b.layer);

      for (const node of sortedNodes) {
        const breath = 1 + node.pulse;
        const r = node.baseRadius * breath;

        // Nodes fade in/out with cascade; barely visible otherwise
        const visibility = node.cascadeGlow;

        // Glow halo
        const glowR = r * 3.0;
        ctx.globalAlpha = visibility * 0.35;
        const glowGrad = ctx.createRadialGradient(
          node.x, node.y, r * 0.5,
          node.x, node.y, glowR,
        );
        glowGrad.addColorStop(0, COL.nodeGlow);
        glowGrad.addColorStop(1, "transparent");
        ctx.fillStyle = glowGrad;
        ctx.beginPath();
        ctx.arc(node.x, node.y, glowR, 0, TAU);
        ctx.fill();

        // Outer halo
        ctx.globalAlpha = visibility * 0.20;
        ctx.fillStyle = COL.nodeGlow;
        ctx.beginPath();
        ctx.arc(node.x, node.y, r * 4.5, 0, TAU);
        ctx.fill();

        // Node body
        const fillAlpha = 0.06 + visibility * 0.72;
        const fillColor = visibility > 0.15 ? COL.nodeCascade : COL.nodeFill;
        ctx.globalAlpha = Math.min(0.9, fillAlpha);
        ctx.fillStyle = fillColor;
        ctx.beginPath();
        ctx.arc(node.x, node.y, r, 0, TAU);
        ctx.fill();

        // Node stroke
        ctx.globalAlpha = 0.06 + visibility * 0.38;
        ctx.strokeStyle = COL.nodeStroke;
        ctx.lineWidth = 0.8;
        ctx.beginPath();
        ctx.arc(node.x, node.y, r, 0, TAU);
        ctx.stroke();
      }

      ctx.globalAlpha = 1;
      animationId = requestAnimationFrame(draw);
    };

    resize();
    window.addEventListener("resize", debouncedResize);
    animationId = requestAnimationFrame(draw);

    return () => {
      window.removeEventListener("resize", debouncedResize);
      if (resizeTimer) clearTimeout(resizeTimer);
      cancelAnimationFrame(animationId);
    };
  }, [initState]);

  return (
    <canvas
      ref={canvasRef}
      aria-hidden="true"
      className="pointer-events-none fixed inset-0 z-0"
    />
  );
}

"use client";

import { useEffect, useRef } from "react";

interface NetNode {
  stage: number;
  idx: number;
  x: number;
  y: number;
  z: number;
  act: number;
  twinkle: number;
}

interface NetEdge {
  a: NetNode;
  b: NetNode;
  w: number;
  tw: number;
  kind: "attn" | "ffn" | "skip";
  ctrlX: number;
  ctrlY: number;
  ctrlZ: number;
}

// Transformer-style block — nodes laid out as 3D rings within each stage.
//   stage 0: token embeddings         (6)  -- ring, radius R0
//   stage 1: attention output         (6)  -- ring, radius R0
//   stage 2: FFN hidden               (12) -- two stacked rings of 6, radius R1
//   stage 3: block output             (6)  -- ring, radius R0
// Stages advance along the X axis. The whole network rotates slowly about
// the vertical (world Y) axis.
const STAGE_SIZES = [6, 6, 12, 6];
const NUM_STAGES = STAGE_SIZES.length;
const N_TOK = STAGE_SIZES[0];

// Attention pattern templates applied to the stage0->stage1 edges.
const PATTERNS: Array<(i: number, j: number) => number> = [
  (i, j) => Math.exp(-Math.abs(i - j) / 1.6), // local window
  (i, j) => (i === j ? 0.95 : 0.28 + 0.12 * ((i + j) % 3)), // mixed diagonal
  (i, j) => (j >= i ? Math.exp(-(j - i) / 2.2) : 0.14), // causal-forward
  (i, j) => (j <= i ? Math.exp(-(i - j) / 2.2) : 0.14), // causal-backward
  (i, j) => Math.exp(-((i - j - 2) ** 2) / 2.4), // shifted peak
  (i, j) => 0.4 + 0.5 * Math.abs(Math.sin((i + 1) * (j + 1) * 0.7)), // global
];

// Single muted slate-blue family. Variation is by alpha only.
const C = {
  edge: "hsl(205, 22%, 52%)",
  skip: "hsl(205, 16%, 44%)",
  pulse: "hsl(200, 30%, 64%)",
  node: "hsl(205, 24%, 58%)",
  pos: "hsl(205, 20%, 50%)",
};
const DASH = [3, 4];
const TAU = Math.PI * 2;

// Camera parameters (world units are roughly screen pixels at depth 0).
const CAM_TILT = -0.42; // X-axis tilt (radians) — look down slightly
const FOCAL = 950;
const CAM_Z = 820;

export default function ParticleField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: true });
    if (!ctx) return;

    let animationId = 0;
    let width = 0;
    let height = 0;
    let dpr = 1;
    let resizeTimer: ReturnType<typeof setTimeout> | null = null;

    let nodes: NetNode[][] = [];
    let edges: NetEdge[] = [];
    let posPoints: Array<{ x: number; y: number; z: number }> = [];
    let runStart = performance.now();
    let nextReset = 30 + Math.random() * 14;
    let cycle = 0;
    let patIdx = Math.floor(Math.random() * PATTERNS.length);

    const ATTN_DUR = 2.8;
    const FFN_DUR = 2.8;
    const SETTLE_DUR = 1.3;
    const CYCLE_DUR = ATTN_DUR + FFN_DUR + SETTLE_DUR;

    const randn = () =>
      (Math.random() + Math.random() + Math.random() - 1.5) * 0.5;

    // Layout parameters (set in buildNetwork).
    let stageSpacingX = 130;
    let ringRadius = 80;
    let ffnRingRadius = 110;
    let ffnRingOffsetY = 22;
    let layoutCy = 0;

    // 3D point → screen. Rotation about world Y, then fixed X-axis tilt.
    const project = (wx: number, wy: number, wz: number, rotY: number) => {
      const cosY = Math.cos(rotY);
      const sinY = Math.sin(rotY);
      const rx = wx * cosY - wz * sinY;
      const rz = wx * sinY + wz * cosY;
      const cosT = Math.cos(CAM_TILT);
      const sinT = Math.sin(CAM_TILT);
      const ty = wy * cosT - rz * sinT;
      const tz = wy * sinT + rz * cosT;
      const denom = CAM_Z + tz;
      const safeDenom = denom > 1 ? denom : 1;
      const scale = FOCAL / safeDenom;
      return {
        sx: width / 2 + rx * scale,
        sy: layoutCy + ty * scale,
        depth: tz,
        scale,
      };
    };

    const buildNetwork = () => {
      nodes = [];
      edges = [];
      posPoints = [];

      const availW = width - 300;
      stageSpacingX = Math.max(110, Math.min(150, availW / (NUM_STAGES - 1)));
      // Ring radii scaled to canvas height.
      const h = height;
      ringRadius = Math.min(75, h * 0.16);
      ffnRingRadius = Math.min(105, h * 0.22);
      ffnRingOffsetY = ringRadius * 0.55;
      layoutCy = height * 0.5;

      // Place nodes: each stage is a ring in the Y-Z plane.
      // 6-token stages: single ring. 12-node FFN stage: two stacked rings of 6.
      for (let s = 0; s < NUM_STAGES; s++) {
        const n = STAGE_SIZES[s];
        const stageNodes: NetNode[] = [];
        const wx = (s - (NUM_STAGES - 1) / 2) * stageSpacingX;

        if (s === 2) {
          // FFN hidden: two stacked rings of 6
          for (let ring = 0; ring < 2; ring++) {
            const yOff = ring === 0 ? -ffnRingOffsetY : ffnRingOffsetY;
            for (let i = 0; i < 6; i++) {
              const ang = (i / 6) * TAU;
              stageNodes.push({
                stage: s,
                idx: ring * 6 + i,
                x: wx,
                y: yOff + Math.cos(ang) * ffnRingRadius,
                z: Math.sin(ang) * ffnRingRadius,
                act: 0,
                twinkle: Math.random() * TAU,
              });
            }
          }
        } else {
          // single ring of n nodes
          for (let i = 0; i < n; i++) {
            const ang = (i / n) * TAU;
            stageNodes.push({
              stage: s,
              idx: i,
              x: wx,
              y: Math.cos(ang) * ringRadius,
              z: Math.sin(ang) * ringRadius,
              act: 0,
              twinkle: Math.random() * TAU,
            });
          }
        }
        nodes.push(stageNodes);
      }

      const pat = PATTERNS[patIdx];
      const addEdge = (a: NetNode, b: NetNode, w: number, kind: NetEdge["kind"]) => {
        const cx = (a.x + b.x) / 2;
        const cy = (a.y + b.y) / 2;
        let cz = (a.z + b.z) / 2;
        if (kind === "skip") {
          // bulge outward (radially from stage axis) in the Y-Z plane
          const r = Math.sqrt(cy * cy + cz * cz);
          const k = r > 1 ? 1.35 : 1;
          cz *= k;
          if (r > 1) {
            // also push the control point a bit along X for arc visibility
          }
        } else {
          // slight bow toward viewer for volume
          const dx = b.x - a.x;
          cz += dx * 0.04;
        }
        edges.push({ a, b, w, tw: w, kind, ctrlX: cx, ctrlY: cy, ctrlZ: cz });
      };

      for (const a of nodes[0]) for (const b of nodes[1]) addEdge(a, b, pat(a.idx, b.idx), "attn");
      for (const a of nodes[1]) for (const b of nodes[2]) addEdge(a, b, randn() * 0.4, "ffn");
      for (const a of nodes[2]) for (const b of nodes[3]) addEdge(a, b, randn() * 0.4, "ffn");
      for (let i = 0; i < N_TOK; i++) {
        addEdge(nodes[0][i], nodes[2][i], randn() * 0.28, "skip");
        addEdge(nodes[1][i], nodes[3][i], randn() * 0.28, "skip");
      }

      // positional encoding: helix encircling the token ring (stage 0)
      const tokX = nodes[0][0].x;
      const helixR = ringRadius * 1.45;
      for (let i = 0; i < N_TOK * 2; i++) {
        const t = i / (N_TOK * 2 - 1);
        const ang = t * TAU * 1.2;
        posPoints.push({
          x: tokX - 8 + Math.sin(t * Math.PI) * 4,
          y: Math.cos(ang) * helixR,
          z: Math.sin(ang) * helixR,
        });
      }
    };

    const resetRun = () => {
      patIdx = (patIdx + 1 + Math.floor(Math.random() * (PATTERNS.length - 1))) % PATTERNS.length;
      const pat = PATTERNS[patIdx];
      for (const e of edges) {
        if (e.kind === "attn") e.tw = pat(e.a.idx, e.b.idx);
        else e.tw += (Math.random() - 0.5) * (e.kind === "skip" ? 0.04 : 0.05);
      }
      runStart = performance.now();
      nextReset = 30 + Math.random() * 14;
      cycle = 0;
    };

    const resize = () => {
      dpr = Math.min(window.devicePixelRatio || 1, 2);
      width = window.innerWidth;
      height = Math.min(380, Math.max(260, Math.floor(window.innerHeight * 0.38)));
      canvas.width = Math.floor(width * dpr);
      canvas.height = Math.floor(height * dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      ctx.fillStyle = "#000000";
      ctx.fillRect(0, 0, width, height);
      buildNetwork();
    };

    const debouncedResize = () => {
      if (resizeTimer) clearTimeout(resizeTimer);
      resizeTimer = setTimeout(resize, 180);
    };

    const fillCircle = (sx: number, sy: number, r: number, color: string, alpha: number) => {
      if (r < 0.2) return;
      ctx.globalAlpha = alpha;
      ctx.fillStyle = color;
      ctx.beginPath();
      ctx.arc(sx, sy, r, 0, TAU);
      ctx.fill();
    };

    const draw = (now: number) => {
      const rt = (now - runStart) * 0.001;
      if (rt > nextReset) resetRun();

      const cycleTime = rt % CYCLE_DUR;
      let phase: "attn" | "ffn" | "settle" = "attn";
      let phaseT = 0;
      if (cycleTime < ATTN_DUR) {
        phase = "attn";
        phaseT = cycleTime / ATTN_DUR;
      } else if (cycleTime < ATTN_DUR + FFN_DUR) {
        phase = "ffn";
        phaseT = (cycleTime - ATTN_DUR) / FFN_DUR;
      } else {
        phase = "settle";
        phaseT = (cycleTime - ATTN_DUR - FFN_DUR) / SETTLE_DUR;
      }

      const curCycle = Math.floor(rt / CYCLE_DUR);
      if (curCycle !== cycle) {
        cycle = curCycle;
        for (const e of edges) {
          if (e.kind !== "attn") e.tw += (Math.random() - 0.5) * 0.03;
        }
        for (const n of nodes[0]) n.twinkle = Math.random() * TAU;
      }

      const updateRate = phase === "settle" ? 0.06 : 0.012;
      for (const e of edges) e.w += (e.tw - e.w) * updateRate;

      let sweepPos = 0;
      if (phase === "attn") sweepPos = phaseT;
      else if (phase === "ffn") sweepPos = 1 + phaseT * 2;
      else sweepPos = 3;

      const queryF = phase === "attn" ? phaseT * N_TOK : -1;

      for (let s = 0; s < NUM_STAGES; s++) {
        const dist = Math.abs(sweepPos - s);
        const bump = Math.exp(-(dist * dist) / 0.5);
        for (const n of nodes[s]) {
          if (phase === "settle") n.act *= 0.8;
          else n.act = Math.max(n.act * 0.84, bump);
        }
      }

      // fade previous frame
      ctx.globalAlpha = 1;
      ctx.fillStyle = "rgba(0, 0, 0, 0.42)";
      ctx.fillRect(0, 0, width, height);

      const rotY = rt * 0.16;
      const isSweeping = phase === "attn" || phase === "ffn";

      // Project all nodes.
      const projNodes: Array<{ n: NetNode; sx: number; sy: number; depth: number; scale: number }> =
        [];
      for (let s = 0; s < NUM_STAGES; s++) {
        for (const n of nodes[s]) {
          const p = project(n.x, n.y, n.z, rotY);
          projNodes.push({ n, sx: p.sx, sy: p.sy, depth: p.depth, scale: p.scale });
        }
      }

      // positional encoding helix
      if (posPoints.length > 0) {
        ctx.globalAlpha = 0.1;
        ctx.strokeStyle = C.pos;
        ctx.lineWidth = 0.7;
        ctx.beginPath();
        for (let i = 0; i < posPoints.length; i++) {
          const p = project(posPoints[i].x, posPoints[i].y, posPoints[i].z, rotY);
          if (i === 0) ctx.moveTo(p.sx, p.sy);
          else ctx.lineTo(p.sx, p.sy);
        }
        ctx.stroke();
        for (const pp of posPoints) {
          const p = project(pp.x, pp.y, pp.z, rotY);
          fillCircle(p.sx, p.sy, 1.0 * p.scale, C.pos, 0.14);
        }
      }

      type DrawItem = { depth: number; fn: () => void };
      const drawItems: DrawItem[] = [];

      // attention + FFN edges
      for (const e of edges) {
        if (e.kind === "skip") continue;
        const a = e.a;
        const b = e.b;
        const lo = a.stage;
        const hi = b.stage;
        const mag = Math.abs(e.w);
        const sweeping = isSweeping && sweepPos >= lo - 0.1 && sweepPos <= hi + 0.1;

        let alpha = 0.02 + mag * 0.07;
        if (sweeping) {
          const span = hi - lo;
          const edgeProgress = Math.max(0, Math.min(1, (sweepPos - lo) / span));
          const prox = Math.sin(
            Math.min(1, Math.max(0, 1 - Math.abs(edgeProgress - 0.5) * 2)) * Math.PI * 0.5,
          );
          alpha += prox * 0.12;
        }
        if (e.kind === "attn" && queryF >= 0) {
          const qprox = Math.exp(-((queryF - b.idx - 0.5) ** 2) / 0.7);
          alpha += qprox * 0.1;
        }

        const pa = project(a.x, a.y, a.z, rotY);
        const pb = project(b.x, b.y, b.z, rotY);
        const avgDepth = (pa.depth + pb.depth) * 0.5;
        const depthFactor = 1 - Math.min(1, Math.max(0, avgDepth / 700)) * 0.55;
        const finalAlpha = Math.min(1, alpha * depthFactor);
        const avgScale = (pa.scale + pb.scale) * 0.5;
        const lw = (0.35 + mag * 0.7) * Math.min(1.3, Math.max(0.5, avgScale));

        drawItems.push({
          depth: avgDepth,
          fn: () => {
            ctx.setLineDash([]);
            ctx.globalAlpha = finalAlpha;
            ctx.strokeStyle = C.edge;
            ctx.lineWidth = lw;
            ctx.beginPath();
            ctx.moveTo(pa.sx, pa.sy);
            ctx.lineTo(pb.sx, pb.sy);
            ctx.stroke();

            if (sweeping && mag > 0.25) {
              const span = hi - lo;
              const edgeProgress = Math.max(0, Math.min(1, (sweepPos - lo) / span));
              const p = edgeProgress;
              const px = pa.sx + (pb.sx - pa.sx) * p;
              const py = pa.sy + (pb.sy - pa.sy) * p;
              fillCircle(px, py, 1.1 * avgScale, C.pulse, 0.35);
            }
          },
        });
      }

      // residual edges (dashed bezier with 3D control point)
      for (const e of edges) {
        if (e.kind !== "skip") continue;
        const a = e.a;
        const b = e.b;
        const lo = a.stage;
        const hi = b.stage;
        const mag = Math.abs(e.w);
        const sweeping = isSweeping && sweepPos >= lo - 0.1 && sweepPos <= hi + 0.1;

        let alpha = 0.03 + mag * 0.06;
        if (sweeping) alpha += 0.07;

        const pa = project(a.x, a.y, a.z, rotY);
        const pb = project(b.x, b.y, b.z, rotY);
        const pc = project(e.ctrlX, e.ctrlY, e.ctrlZ, rotY);
        const avgDepth = (pa.depth + pb.depth) * 0.5;
        const depthFactor = 1 - Math.min(1, Math.max(0, avgDepth / 700)) * 0.55;
        const finalAlpha = Math.min(1, alpha * depthFactor);
        const avgScale = (pa.scale + pb.scale) * 0.5;
        const lw = (0.35 + mag * 0.5) * Math.min(1.3, Math.max(0.5, avgScale));

        drawItems.push({
          depth: avgDepth,
          fn: () => {
            ctx.setLineDash(DASH);
            ctx.globalAlpha = finalAlpha;
            ctx.strokeStyle = C.skip;
            ctx.lineWidth = lw;
            ctx.beginPath();
            ctx.moveTo(pa.sx, pa.sy);
            ctx.quadraticCurveTo(pc.sx, pc.sy, pb.sx, pb.sy);
            ctx.stroke();
          },
        });
      }

      drawItems.sort((x, y) => y.depth - x.depth);
      for (const it of drawItems) it.fn();
      ctx.setLineDash([]);

      // nodes — back-to-front
      projNodes.sort((x, y) => y.depth - x.depth);
      for (const { n, sx, sy, scale } of projNodes) {
        const isEdge = n.stage === 0 || n.stage === NUM_STAGES - 1;
        const baseR = (isEdge ? 2.8 : 2.2) * Math.min(1.3, Math.max(0.5, scale));
        const inputBoost = n.stage === 0 ? 0.18 + 0.12 * Math.sin(rt * 0.8 + n.twinkle) : 0;
        const glow = Math.max(n.act, Math.max(0, inputBoost));
        const r = baseR + glow * 1.2;
        const depthFactor = 1 - Math.min(1, Math.max(0, (1 - scale) * 0.8)) * 0.4;

        if (glow > 0.05) {
          fillCircle(sx, sy, r * 2.4, C.node, glow * 0.07 * depthFactor);
        }
        fillCircle(sx, sy, r, C.node, (0.32 + glow * 0.2) * depthFactor);
      }

      ctx.globalAlpha = 1;
      animationId = requestAnimationFrame(draw);
    };

    resize();
    resetRun();
    window.addEventListener("resize", debouncedResize);
    animationId = requestAnimationFrame(draw);

    return () => {
      window.removeEventListener("resize", debouncedResize);
      if (resizeTimer) clearTimeout(resizeTimer);
      cancelAnimationFrame(animationId);
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      aria-hidden="true"
      className="pointer-events-none fixed inset-x-0 top-0 z-0 block"
    />
  );
}

"use client";

import { useEffect, useRef } from "react";

// 3D diffusion field powered by jax-js.
//
// A cloud of particles undergoes overdamped Langevin dynamics (an
// Ornstein-Uhlenbeck process) with an added swirling advection field:
//
//   dx = (-kappa * x + alpha * cross(x, axis)) * dt + sigma * sqrt(dt) * N(0,1)
//
// All vectorized array ops run on jax-js (WebGPU when available, else Wasm)
// and are fused into a single kernel via jit(). Positions are read back each
// frame and projected onto a 2D canvas with a slowly rotating perspective
// camera. Motion trails come from a translucent black overlay each frame plus
// streak lines between consecutive projected positions.

const TAU = Math.PI * 2;
const N_PARTICLES = 1200;
const DT = 0.06;
const KAPPA = 0.18; // harmonic confinement (OU drift)
const SIGMA = 0.7; // diffusion (noise) scale
const SWIRL = 0.9; // rotational advection strength

// Slate-blue family, varied by alpha.
const COL_CORE = "hsl(205, 32%, 66%)";
const COL_HALO = "hsl(205, 26%, 52%)";
const COL_HOT = "hsl(198, 42%, 76%)";

type JaxArray = import("@jax-js/jax").Array;
type JaxModule = typeof import("@jax-js/jax");

export default function DiffusionField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d", { alpha: true });
    if (!ctx) return;

    let animationId = 0;
    let disposed = false;
    let width = 0;
    let height = 0;
    let dpr = 1;
    let resizeTimer: ReturnType<typeof setTimeout> | null = null;

    let jax: JaxModule | null = null;
    let key: JaxArray | null = null;
    let X: JaxArray | null = null;
    let stepJit: ((x: JaxArray, k: JaxArray) => [JaxArray, JaxArray]) | null = null;
    let prevScreen: Float32Array | null = null;

    const resize = () => {
      dpr = Math.min(window.devicePixelRatio || 1, 2);
      width = window.innerWidth;
      height = Math.min(420, Math.max(280, Math.floor(window.innerHeight * 0.42)));
      canvas.width = Math.floor(width * dpr);
      canvas.height = Math.floor(height * dpr);
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;
      ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
      ctx.fillStyle = "#000000";
      ctx.fillRect(0, 0, width, height);
      prevScreen = null;
    };

    const debouncedResize = () => {
      if (resizeTimer) clearTimeout(resizeTimer);
      resizeTimer = setTimeout(resize, 180);
    };

    const setupJax = async () => {
      jax = await import("@jax-js/jax");
      const np = jax.numpy;
      const random = jax.random;
      const { jit } = jax;

      try {
        const devices = await jax.init();
        if (devices.includes("webgpu")) jax.defaultDevice("webgpu");
      } catch {
        // fall back to default wasm device
      }

      key = random.key(20260618);
      const [k0, k1] = random.split(key, 2);
      key = k0;
      X = random.normal(k1, [N_PARTICLES, 3]).mul(0.5);

      // Swirl axis (constant, baked into the compiled kernel).
      const axis = np.array([0.35, 1.0, 0.25], { dtype: np.float32 });

      // One fused step: overdamped Langevin SDE.
    //   dx = (-kappa * x + alpha * cross(x, axis)) * dt + sigma * sqrt(dt) * noise
    //   x' = x + dx
    //   k' = split(k)[0]
      stepJit = jit(function step(x: JaxArray, k: JaxArray): [JaxArray, JaxArray] {
        // x is used 3 times: neg (drift), cross (swirl), add (update).
        const drift = x.ref.neg().mul(KAPPA);
        const swirl = np.cross(x.ref, axis).mul(SWIRL);
        const [kNext, kNoise] = random.split(k, 2);
        const noise = random.normal(kNoise, [N_PARTICLES, 3]);
        const sqrtDt = Math.sqrt(DT);
        const dx = drift.add(swirl).mul(DT).add(noise.mul(SIGMA * sqrtDt));
        const newX = x.add(dx);
        return [newX, kNext];
      });
    };

    const project = (
      wx: number,
      wy: number,
      wz: number,
      cosY: number,
      sinY: number,
      cosT: number,
      sinT: number,
      cx: number,
      cy: number,
    ) => {
      const rx = wx * cosY - wz * sinY;
      const rz = wx * sinY + wz * cosY;
      const ty = wy * cosT - rz * sinT;
      const tz = wy * sinT + rz * cosT;
      const denom = 9.5 + tz;
      const scale = 760 / (denom > 0.1 ? denom : 0.1);
      return { sx: cx + rx * scale, sy: cy + ty * scale, depth: tz, scale };
    };

    const draw = async () => {
      if (!jax || !stepJit || !X || !key) {
        if (!disposed) animationId = requestAnimationFrame(draw);
        return;
      }

      const t = performance.now() * 0.001;

      // Run two fused steps per frame for richer motion.
      try {
        const r1 = stepJit(X, key);
        X = r1[0];
        key = r1[1];
        const r2 = stepJit(X, key);
        X = r2[0];
        key = r2[1];
      } catch {
        if (!disposed) animationId = requestAnimationFrame(draw);
        return;
      }

      const data = await X.data();
      const pos = data as Float32Array;

      // Fade prior frame for motion trails.
      ctx.globalAlpha = 1;
      ctx.fillStyle = "rgba(0, 0, 0, 0.32)";
      ctx.fillRect(0, 0, width, height);

      const cx = width / 2;
      const cy = height / 2;
      const rotY = t * 0.14;
      const cosY = Math.cos(rotY);
      const sinY = Math.sin(rotY);
      const tilt = -0.34;
      const cosT = Math.cos(tilt);
      const sinT = Math.sin(tilt);

      type Item = {
        sx: number;
        sy: number;
        r: number;
        a: number;
        depth: number;
        psx: number;
        psy: number;
      };
      const items: Item[] = [];
      const prev = prevScreen;

      for (let i = 0; i < N_PARTICLES; i++) {
        const p = project(
          pos[i * 3],
          pos[i * 3 + 1],
          pos[i * 3 + 2],
          cosY,
          sinY,
          cosT,
          sinT,
          cx,
          cy,
        );
        const depthFade = 1 - Math.min(1, Math.max(0, (p.depth - 2) / 9)) * 0.6;
        const r = Math.max(0.4, 1.0 + p.scale * 0.045);
        items.push({
          sx: p.sx,
          sy: p.sy,
          r,
          a: depthFade,
          depth: p.depth,
          psx: prev ? prev[i * 2] : p.sx,
          psy: prev ? prev[i * 2 + 1] : p.sy,
        });
      }

      // Sort back-to-front by depth.
      items.sort((a, b) => b.depth - a.depth);

      for (const it of items) {
        // Streak from previous to current position.
        if (prev && (Math.abs(it.sx - it.psx) > 0.3 || Math.abs(it.sy - it.psy) > 0.3)) {
          ctx.globalAlpha = it.a * 0.35;
          ctx.strokeStyle = COL_HALO;
          ctx.lineWidth = it.r * 0.85;
          ctx.beginPath();
          ctx.moveTo(it.psx, it.psy);
          ctx.lineTo(it.sx, it.sy);
          ctx.stroke();
        }
        // Halo.
        ctx.globalAlpha = it.a * 0.18;
        ctx.fillStyle = COL_HALO;
        ctx.beginPath();
        ctx.arc(it.sx, it.sy, it.r * 2.6, 0, TAU);
        ctx.fill();
        // Core.
        ctx.globalAlpha = it.a * 0.85;
        ctx.fillStyle = COL_CORE;
        ctx.beginPath();
        ctx.arc(it.sx, it.sy, it.r, 0, TAU);
        ctx.fill();
      }

      // Hot highlights on a sparse subset for sparkle.
      for (let i = 0; i < items.length; i += 23) {
        const it = items[i];
        ctx.globalAlpha = it.a * 0.6;
        ctx.fillStyle = COL_HOT;
        ctx.beginPath();
        ctx.arc(it.sx, it.sy, it.r * 0.65, 0, TAU);
        ctx.fill();
      }

      // Store projected positions for next frame's streaks.
      if (!prevScreen || prevScreen.length !== N_PARTICLES * 2) {
        prevScreen = new Float32Array(N_PARTICLES * 2);
      }
      // Need to store in original index order, not sorted order.
      for (let i = 0; i < N_PARTICLES; i++) {
        const p = project(
          pos[i * 3],
          pos[i * 3 + 1],
          pos[i * 3 + 2],
          cosY,
          sinY,
          cosT,
          sinT,
          cx,
          cy,
        );
        prevScreen[i * 2] = p.sx;
        prevScreen[i * 2 + 1] = p.sy;
      }

      ctx.globalAlpha = 1;
      if (!disposed) animationId = requestAnimationFrame(draw);
    };

    resize();
    window.addEventListener("resize", debouncedResize);

    setupJax()
      .then(() => {
        if (!disposed) animationId = requestAnimationFrame(draw);
      })
      .catch((err) => {
        console.warn("DiffusionField: jax-js init failed, rendering fallback.", err);
        ctx.fillStyle = "#000000";
        ctx.fillRect(0, 0, width, height);
        const g = ctx.createRadialGradient(
          width / 2,
          height / 2,
          0,
          width / 2,
          height / 2,
          Math.max(width, height) * 0.7,
        );
        g.addColorStop(0, "rgba(40, 70, 110, 0.45)");
        g.addColorStop(1, "rgba(0, 0, 0, 0)");
        ctx.fillStyle = g;
        ctx.fillRect(0, 0, width, height);
      });

    return () => {
      disposed = true;
      window.removeEventListener("resize", debouncedResize);
      if (resizeTimer) clearTimeout(resizeTimer);
      cancelAnimationFrame(animationId);
      try {
        X?.dispose();
        key?.dispose();
      } catch {
        // ignore
      }
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      aria-hidden="true"
      className="pointer-events-none fixed inset-x-0 top-0 z-0 block"
    />
  );
}

"use client";

import { useEffect, useRef } from "react";

// Isometric pixel art landscape drawn on Canvas
export default function PixelLandscape() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    const W = canvas.width;
    const H = canvas.height;

    // Clear to dark grid background
    ctx.fillStyle = "#2a2a2a";
    ctx.fillRect(0, 0, W, H);

    // Draw faint grid lines
    ctx.strokeStyle = "#3a3a3a";
    ctx.lineWidth = 1;
    for (let x = 0; x < W; x += 20) {
      ctx.beginPath();
      ctx.moveTo(x, 0);
      ctx.lineTo(x, H);
      ctx.stroke();
    }
    for (let y = 0; y < H; y += 20) {
      ctx.beginPath();
      ctx.moveTo(0, y);
      ctx.lineTo(W, y);
      ctx.stroke();
    }

    // Isometric parameters
    const tileW = 24;
    const tileH = 12;
    const offsetX = W / 2;
    const offsetY = H / 3;

    // Simple height map: returns elevation at grid coordinate
    function heightAt(gx: number, gy: number): number {
      const cx1 = 6,
        cy1 = 6,
        r1 = 5;
      const cx2 = 14,
        cy2 = 10,
        r2 = 4;
      const d1 = Math.sqrt((gx - cx1) ** 2 + (gy - cy1) ** 2);
      const d2 = Math.sqrt((gx - cx2) ** 2 + (gy - cy2) ** 2);
      let h = 0;
      if (d1 < r1) h += Math.max(0, (r1 - d1) * 18);
      if (d2 < r2) h += Math.max(0, (r2 - d2) * 14);
      // base rolling terrain
      h += Math.sin(gx * 0.4) * 4 + Math.cos(gy * 0.3) * 4;
      return Math.max(0, h);
    }

    function isoX(gx: number, gy: number) {
      return offsetX + (gx - gy) * tileW;
    }
    function isoY(gx: number, gy: number, h: number) {
      return offsetY + (gx + gy) * tileH - h;
    }

    const gridSize = 22;
    const terrain: number[][] = [];
    for (let y = 0; y < gridSize; y++) {
      terrain[y] = [];
      for (let x = 0; x < gridSize; x++) {
        terrain[y][x] = heightAt(x, y);
      }
    }

    // Draw terrain tiles back-to-front
    for (let gy = 0; gy < gridSize; gy++) {
      for (let gx = 0; gx < gridSize; gx++) {
        const h = terrain[gy][gx];
        const x = isoX(gx, gy);
        const y = isoY(gx, gy, h);

        // Determine surface color
        const dCenter = Math.sqrt((gx - 8) ** 2 + (gy - 8) ** 2);
        let surface = h > 25 ? "#8a8a7a" : dCenter < 7 ? "#6b8f5e" : "#c2b280";
        if (h < 2) surface = "#b8a868";
        if (h > 35) surface = "#9a9a8a";

        // Draw top face
        ctx.fillStyle = surface;
        ctx.beginPath();
        ctx.moveTo(x, y);
        ctx.lineTo(x + tileW, y + tileH);
        ctx.lineTo(x, y + tileH * 2);
        ctx.lineTo(x - tileW, y + tileH);
        ctx.closePath();
        ctx.fill();

        // Draw left side if exposed
        if (gx === 0 || terrain[gy][gx - 1] < h) {
          ctx.fillStyle = shade(surface, -20);
          ctx.beginPath();
          ctx.moveTo(x - tileW, y + tileH);
          ctx.lineTo(x, y + tileH * 2);
          ctx.lineTo(x, y + tileH * 2 + h);
          ctx.lineTo(x - tileW, y + tileH + h);
          ctx.closePath();
          ctx.fill();
        }

        // Draw right side if exposed
        if (gy === gridSize - 1 || terrain[gy + 1]?.[gx] < h) {
          ctx.fillStyle = shade(surface, -35);
          ctx.beginPath();
          ctx.moveTo(x + tileW, y + tileH);
          ctx.lineTo(x, y + tileH * 2);
          ctx.lineTo(x, y + tileH * 2 + h);
          ctx.lineTo(x + tileW, y + tileH + h);
          ctx.closePath();
          ctx.fill();
        }
      }
    }

    // Draw wireframe cliffs (darker edges)
    ctx.strokeStyle = "#555";
    ctx.lineWidth = 1;
    for (let gy = 0; gy < gridSize; gy++) {
      for (let gx = 0; gx < gridSize; gx++) {
        const h = terrain[gy][gx];
        const x = isoX(gx, gy);
        const y = isoY(gx, gy, h);
        const below = gy < gridSize - 1 ? terrain[gy + 1][gx] : 0;
        if (below < h - 5) {
          ctx.beginPath();
          ctx.moveTo(x, y + tileH * 2);
          ctx.lineTo(x, y + tileH * 2 + (h - below));
          ctx.stroke();
          ctx.beginPath();
          ctx.moveTo(x - tileW, y + tileH);
          ctx.lineTo(x - tileW, y + tileH + (h - below));
          ctx.stroke();
          ctx.beginPath();
          ctx.moveTo(x + tileW, y + tileH);
          ctx.lineTo(x + tileW, y + tileH + (h - below));
          ctx.stroke();
        }
      }
    }

    // Draw trees on green tiles
    for (let gy = 0; gy < gridSize; gy++) {
      for (let gx = 0; gx < gridSize; gx++) {
        const h = terrain[gy][gx];
        const dCenter = Math.sqrt((gx - 8) ** 2 + (gy - 8) ** 2);
        if (h > 2 && h < 28 && dCenter < 7 && Math.random() > 0.6) {
          const x = isoX(gx, gy);
          const y = isoY(gx, gy, h) + tileH;
          drawTree(ctx, x, y);
        }
      }
    }

    // Draw a wireframe tower in center
    const tx = 8,
      ty = 8;
    const th = terrain[ty][tx] + 5;
    const txIso = isoX(tx, ty);
    const tyIso = isoY(tx, ty, th);
    drawWireframeTower(ctx, txIso, tyIso, 30);

    // Draw flying saucers
    drawSaucer(ctx, isoX(4, 2) - 40, isoY(4, 2, terrain[2][4]) - 80, 18);
    drawSaucer(ctx, isoX(10, 3) + 20, isoY(10, 3, terrain[3][10]) - 100, 22);
    drawSaucer(ctx, isoX(16, 5) - 10, isoY(16, 5, terrain[5][16]) - 70, 16);
    drawSaucer(ctx, isoX(7, 16) + 30, isoY(7, 16, terrain[16][7]) - 90, 20);
    drawSaucer(ctx, isoX(18, 18) - 30, isoY(18, 18, terrain[18][18]) - 60, 14);

    function shade(hex: string, amount: number) {
      const num = parseInt(hex.replace("#", ""), 16);
      const r = Math.max(0, Math.min(255, (num >> 16) + amount));
      const g = Math.max(0, Math.min(255, ((num >> 8) & 0x00ff) + amount));
      const b = Math.max(0, Math.min(255, (num & 0x0000ff) + amount));
      return `#${(r << 16 | g << 8 | b).toString(16).padStart(6, "0")}`;
    }

    function drawTree(
      c: CanvasRenderingContext2D,
      x: number,
      y: number,
    ) {
      // Trunk
      c.fillStyle = "#3e2b1f";
      c.fillRect(x - 1, y - 8, 2, 8);
      // Leaves (three layered circles)
      const greens = ["#4a7c3f", "#5a9a4a", "#6bb85a"];
      greens.forEach((col, i) => {
        c.fillStyle = col;
        c.beginPath();
        c.arc(x, y - 10 - i * 5, 5 - i, 0, Math.PI * 2);
        c.fill();
      });
    }

    function drawWireframeTower(
      c: CanvasRenderingContext2D,
      x: number,
      y: number,
      h: number,
    ) {
      c.strokeStyle = "#aaa";
      c.lineWidth = 1.5;
      const w = 12;
      // Vertical lines
      for (let i = 0; i < 4; i++) {
        const ox = x + (i % 2 === 0 ? -w : w) + (i < 2 ? -w / 2 : w / 2);
        const oy = y + (i < 2 ? -tileH : tileH) * 0.5;
        c.beginPath();
        c.moveTo(ox, oy);
        c.lineTo(ox, oy - h);
        c.stroke();
      }
      // Horizontal rings
      for (let r = 0; r < 5; r++) {
        const ry = y - (h / 5) * r;
        c.beginPath();
        c.moveTo(x - w, ry - tileH * 0.5);
        c.lineTo(x, ry);
        c.lineTo(x + w, ry - tileH * 0.5);
        c.lineTo(x, ry - tileH);
        c.closePath();
        c.stroke();
      }
    }

    function drawSaucer(
      c: CanvasRenderingContext2D,
      x: number,
      y: number,
      size: number,
    ) {
      // Hull
      c.fillStyle = "#a05a2c";
      c.beginPath();
      c.ellipse(x, y, size, size * 0.35, 0, 0, Math.PI * 2);
      c.fill();
      // Dark underside
      c.fillStyle = "#6b3a1a";
      c.beginPath();
      c.ellipse(x, y + 2, size * 0.7, size * 0.2, 0, 0, Math.PI * 2);
      c.fill();
      // Grid hatch
      c.strokeStyle = "#3a2210";
      c.lineWidth = 1;
      for (let i = -size + 4; i < size - 4; i += 5) {
        c.beginPath();
        c.moveTo(x + i, y - size * 0.25);
        c.lineTo(x + i, y + size * 0.25);
        c.stroke();
      }
      // Small fin
      c.fillStyle = "#8a4a20";
      c.fillRect(x - 2, y - size * 0.35 - 6, 4, 6);
    }
  }, []);

  return (
    <canvas
      ref={canvasRef}
      width={800}
